import { ResponsiveBar } from "@nivo/bar";
import { tokens } from "../theme";
import { mockBarData as data } from "../data/mockData";
import { colorSchemes } from "@nivo/colors";
import secureLocalStorage from 'react-secure-storage';
import axios from "axios";

const BarChart = ({isDashboard, safraId}) => {
  const token = secureLocalStorage.getItem('auth_token');
  const theme = useTheme();
  const colors = tokens(theme.palette.mode);
  const isMobile = useMediaQuery("(max-width: 800px)");
  const isSmallDivice = useMediaQuery("(max-width: 1400px)");
  const isMediumDivice = useMediaQuery("(max-width: 1800px)");
  const nivoColors = colorSchemes.nivo;

  const [userData, setUserData] = useState(null);
  const [barData, setBarData] = useState([]);

  useEffect(() => {
    const storedUser = secureLocalStorage.getItem('userData'); 
    if (storedUser) {
      setUserData(JSON.parse(storedUser));
    }
  }, []);

  useEffect(() => {
    if (userData && userData.email) { 
      const fetchBarData = async () => {
        try {
          const response = await axios.get(`http://localhost:3000/custos-categoria-bar-chart`, {
            params: { id: safraId }, headers: {Authorization: `Bearer ${token}`}
          });
                      
          setBarData(response.data); 
                        
        } catch (error) {
          if (error.response?.status === 401) {
            alert('Sessão expirada. Faça login novamente.');
            secureLocalStorage.removeItem('userData');
            secureLocalStorage.removeItem('auth_token');
            window.location.href = '/login';
          } else {
            console.log("ERRO - ao buscar no banco de dados.");
          }
        }
      };
      fetchBarData();
    }
  }, [userData]);  


  return (
    <ResponsiveBar
      data={barData}
      theme={{
        // added
        axis: {
          domain: {
            line: {
              stroke: colors.grey[100],
            },
          },
          legend: {
            text: {
              fill: colors.grey[100],
            },
          },
          ticks: {
            line: {
              stroke: colors.grey[100],
              strokeWidth: 1,
            },
            text: {
              fill: colors.grey[100],
            },
          },
        },
        legends: {
          text: {
            fill: colors.grey[100],
          },
        },
        tooltip: {
            container: {
                color: (theme.palette.mode === 'dark' ? colors.grey[800] : colors.grey[100]),
            },
        }
      }}
      keys={["value"]}
      indexBy="category"
      margin={{ top: 50, right: 60, bottom: 50, left: 90 }}
      padding={0.3}
      layout="horizontal"
      valueScale={{ type: "linear" }}
      indexScale={{ type: "band", round: true }}
      colors={(bar) => nivoColors[bar.index % nivoColors.length]}
      defs={[
        {
          id: "dots",
          type: "patternDots",
          background: "inherit",
          color: "#38bcb2",
          size: 4,
          padding: 1,
          stagger: true,
        },
        {
          id: "lines",
          type: "patternLines",
          background: "inherit",
          color: "#eed312",
          rotation: -45,
          lineWidth: 6,
          spacing: 10,
        },
      ]}
      borderColor={{
        from: "color",
        modifiers: [["darker", "1.6"]],
      }}
      axisTop={null}
      axisRight={null}
      axisBottom={{
        tickSize: isSmallDivice ? 0 : 5, 
        tickPadding: isSmallDivice ? 0 : 5,
        tickRotation: isSmallDivice ? 0 : 0, 
        legend: isDashboard ? undefined : "gleba", 
        legendPosition: "middle",
        legendOffset: 32,
        format: isSmallDivice ? () => "" : undefined,
      }}
      axisLeft={{
        tickSize: 5,
        tickPadding: 5,
        tickRotation: 0,
        legend: undefined, 
        legendPosition: "middle",
        legendOffset: -40,
      }}
      enableLabel={true}
      labelSkipWidth={12}
      labelSkipHeight={12}
      labelTextColor={{
        from: "color",
        modifiers: [["darker", 1.6]],
      }}
      legends={
        true ? []:
        [
        {
          dataFrom: "keys",
          anchor: "bottom-right",
          direction: "column",
          justify: false,
          translateX: 120,
          translateY: 0,
          itemsSpacing: 2,
          itemWidth: 100,
          itemHeight: 20,
          itemDirection: "left-to-right",
          itemOpacity: 0.85,
          symbolSize: 20,
          effects: [
            {
              on: "hover",
              style: {
                itemOpacity: 1,
              },
            },
          ],
        },
      ]}
      role="application"
      barAriaLabel={function (e) {
        return e.id + ": " + e.formattedValue + " in country: " + e.indexValue;
      }}
    />
  );
};

