import { Typography, Box, useTheme } from "@mui/material";
import { tokens } from "../theme";

const Header = ({ title, subtitle }) => {
  const theme = useTheme();
  const colors = tokens(theme.palette.mode);
  return (
    <Box mb="30px">
      <Typography
        variant="h2"
        color={colors.grey[100]}
        fontWeight="bold"
        sx={{ m: "0 0 5px 0" }}
      >
        {title}
      </Typography>
      <Typography variant="h5" color={colors.mygreen[800]}>
        {subtitle}
      </Typography>
    </Box>
  );
};

export default Header;

import { Box, Typography, useTheme } from "@mui/material";
import { tokens } from "../theme";

const InfoBox = ({ title, subtitle, icon }) => {
  const theme = useTheme();
  const colors = tokens(theme.palette.mode);

  return (
    <Box
      width="100%"
      m="0 30px"
      display="flex"
      flexDirection="column"
      alignItems="center"
      justifyContent="center"
      textAlign="center"
    >
      <Box>
        {icon}
        <Typography
          variant="h3"
          fontWeight="bold"
          sx={{ color: colors.grey[100] }}
        >
          {title}
        </Typography>
      </Box>
      <Box mt="2px">
        <Typography variant="h5" sx={{ color: colors.mygreen[500] }}>
          {subtitle}
        </Typography>
      </Box>
    </Box>
  );
};

export default InfoBox;

import React, { useState, useEffect } from "react";
import { ResponsiveLine } from "@nivo/line";
import { useTheme, useMediaQuery } from "@mui/material";
import { tokens } from "../theme";
import { mockLineData2 as data } from "../data/mockData";
import secureLocalStorage from 'react-secure-storage';
import axios from "axios";

const LineChart = ({ isDashboard , safraId}) => {
  const token = secureLocalStorage.getItem('auth_token');
  const theme = useTheme();
  const colors = tokens(theme.palette.mode);
  const isMobile = useMediaQuery("(max-width: 800px)");
  const isSmallDivice = useMediaQuery("(max-width: 1000px)");
  const isMediumDivice = useMediaQuery("(max-width: 1800px)");
  const [userData, setUserData] = useState(null);
  const [lineData, setLineData] = useState([]);

  useEffect(() => {
    const storedUser = secureLocalStorage.getItem('userData'); 
    if (storedUser) {
      setUserData(JSON.parse(storedUser));
    }
  }, []);

useEffect(() => {
  if (userData && userData.email) { 
    const fetchLineData = async () => {
      try {
        const response = await axios.get(`http://localhost:3000/custos-glebas-line-chart`, {
          params: { safraId: 1 }, headers: {Authorization: `Bearer ${token}`}
        });
                    
        setLineData(response.data);                       
      } catch (error) {
        if (error.response?.status === 401) {
            alert('Sessão expirada. Faça login novamente.');
            secureLocalStorage.removeItem('userData');
            secureLocalStorage.removeItem('auth_token');
            window.location.href = '/login';
          } else {
          console.log("ERRO - ao buscar no banco de dados.");
        }
      }
    };
    fetchLineData();
  }
}, [userData]);  

  // Função para formatação de valores em dinheiro
  const formatCurrency = (value) => {
    return `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  return (
    <ResponsiveLine
      data={lineData}
      theme={{
        axis: {
          domain: {
            line: {
              stroke: colors.grey[100],
            },
          },
          legend: {
            text: {
              fill: colors.grey[100],
            },
          },
          ticks: {
            line: {
              stroke: colors.grey[100],
              strokeWidth: 1,
            },
            text: {
              fill: colors.grey[100],
            },
          },
        },
        legends: {
          text: {
            fill: colors.grey[100],
          },
