                    value={
                      values.property
                        ? propertyOptions.find((option) => option.id === values.property) 
                        : null
                    } 
                    onChange={(event, value) => setFieldValue('property', value?.id || null)} 
                    onBlur={handleBlur} 
                    sx={{ gridColumn: "span 2" }}
                    renderInput={(params) => (
                      <TextField 
                        {...params} 
                        label="Propriedade"
