            alignItems: 'center',
            backgroundColor: '#fff',
            padding: 4,
            borderRadius: '3px 0 0 3px',
          }}
        >
            <Avatar style={avatarStyle}>
                <AgricultureIcon sx={{ fontSize: 50 }} />
