              <Button 
                onClick={handleOpenModalGleba}
                sx={{ 
                  backgroundColor: colors.mygreen[400],
                  color: colors.grey[100],
                  fontSize: "12px",
                  fontWeight: "bold",
                  marginLeft: "10px",
                  "&:hover": {
                    backgroundColor: colors.grey[700], 
                  },
                }} 
                variant="contained"
              >
                Adicionar Talhão
              </Button>
              <Modal
                open={openModalGleba}
                onClose={null} 
                aria-labelledby="transition-modal-title"
                aria-describedby="transition-modal-description"
                closeAfterTransition
                slots={{ backdrop: Backdrop }}
                slotProps={{
                  backdrop: {
                    timeout: 500,
                  },
                }}
              >
                <Fade in={openModalGleba}>
                  <Box 
                    color={colors.grey[100]}
                    backgroundColor={colors.primary[400]}
                    sx={{ 
                      position: 'absolute',
                      top: '50%',
                      left: '50%',
                      transform: 'translate(-50%, -50%)',
                      width: 450,
                      borderRadius: 3, 
                      boxShadow: '0px 10px 30px rgba(0, 0, 0, 0.1)',
                      p: 4,
                    }}
                  >
                    <Typography id="modal-modal-title" variant="h4" component="h2" >
                      Adicionar Talhão
                    </Typography>
                    <Box
                      gridColumn="span 12"
                      display="grid"
                      gridTemplateColumns={isMobile ? "1fr" : "repeat(1, 1fr)"}
                      padding="25px 0px"
                    >
                      <Box display="flex" flexWrap="wrap" gap="10px">
                        {glebas && glebas.map((gleba, index) => (
                          <Chip
                            key={index}
                            label={gleba.name} 
                            sx={{ padding: "10px", fontWeight: "bold", flexShrink: 0 }}
                          />
                        ))}
                      </Box>
                    </Box>    
                    <Typography variant="body1" sx={{ mb: "20px", color: theme.palette.mode === 'dark' ? colors.primary[100] : colors.grey[600] }}>
                      <IconButton sx={{ p: 0, mr: 1 }}>
                        <InfoIcon fontSize="small" />
                      </IconButton>
                        Uma vez que um Talhão é adicionado à uma Safra, essa ação não pode ser desfeita!
                    </Typography>
                    <Autocomplete
                      disablePortal
                      id="glebas"
                      multiple 
                      options={glebaOptions}
                      getOptionLabel={(option) => option.name || ""}
                      name="glebas"
                      value={
                        values.glebas && values.glebas.length > 0
                        ? glebaOptions.filter((option) => values.glebas.includes(option.id)) 
                        : []
                      }
                      onChange={(event, newValue) => {
                        setFieldValue('glebas', newValue.map((option) => option.id));
                      }}
                      onBlur={handleBlur}
                      sx={{ gridColumn: isSmallDevice ? "span 4" : "span 2" }}
                    
                      renderInput={(params) => (
                        <TextField
                          {...params}
                          label="Talhão"
                          variant="filled"
                          name="glebas"
                          error={!!touched.glebas && !!errors.glebas}
                          helperText={touched.glebas && errors.glebas}
                          onBlur={handleBlur}
                        />
                      )}
                      noOptionsText="Nenhum talhão disponível"
                      />                                         
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
                        <Button 
                          onClick={() => {
                            setFieldValue('glebas', '');
                            setOpenModalGleba(false);
                          }} 
                            sx={{
                            color: colors.redAccent[500]
                          }}
                        >
                          Sair
                        </Button>
                        <Button 
                          onClick={handleAdicionarGleba} 
                          variant="contained" 
                          sx={{ 
                            color: colors.grey[100],
                            fontWeight: "bold",
                            backgroundColor:  colors.mygreen[400],
                            "&:hover": {
                              backgroundColor: colors.grey[700], 
                            },
                          }}
                        >
                        Salvar
                      </Button>
                    </Box>
                  </Box>
                </Fade>
              </Modal>              
              <Button 
                onClick={handleOpenModalSafra}
                sx={{ 
                  backgroundColor: colors.blueAccent[500],
                  color: colors.grey[100],
                  fontSize: "12px",
                  fontWeight: "bold",
                  marginLeft: "10px",
                  "&:hover": {
                    backgroundColor: colors.grey[700], 
                  },
                }} 
                variant="contained"
                disabled={values.type === "Planejado"}
              >
                Finalizar Safra
              </Button>
              <Modal
                open={openModalSafra}
                onClose={null} 
                aria-labelledby="transition-modal-title"
                aria-describedby="transition-modal-description"
                closeAfterTransition
                slots={{ backdrop: Backdrop }}
                slotProps={{
                  backdrop: {
                    timeout: 500,
                  },
                }}
              >
                <Fade in={openModalSafra}>
                  <Box 
                    color={colors.grey[100]}
                    backgroundColor={colors.primary[400]}
                    sx={{ 
                      position: 'absolute',
                      top: '50%',
                      left: '50%',
                      transform: 'translate(-50%, -50%)',
                      width: 450,
                      borderRadius: 3, 
                      boxShadow: '0px 10px 30px rgba(0, 0, 0, 0.1)',
                      p: 4,
                    }}
                  >
                    <Typography id="modal-modal-title" variant="h4" component="h2" >
                      Deseja realmente finalizar esta Safra ?
                    </Typography>
                     <Typography id="modal-modal-description" sx={{ mt: 2 }}>
                        Ao fazer isso, esteja ciente que:
                        <ul>
                          <li>Essa ação não pode ser revertida;</li>
                          <li>Você não poderá mais editar os dados desta Safra.</li>
                        </ul>
                    </Typography> 
                    <FormControlLabel
                      control={
                        <Checkbox
                          checked={isChecked}
                          onChange={handleCheckboxChange} 
                        />
                      }
                      label="Estou ciente e quero continuar."
                      sx={{ mt: 2 }}
                    />                                        
                      <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
                        <Button 
                          onClick={() => {
                            setOpenModalSafra(false);
                            setIsChecked(false);
                          }}
                            sx={{
                            color: colors.redAccent[500]
                          }}
                        >
                          Sair
                        </Button>
                        <Button 
                          onClick={handleFinalizar} 
                          variant="contained" 
                          sx={{ 
                            color: colors.grey[100],
                            fontWeight: "bold",
                            backgroundColor: colors.blueAccent[500],
                            "&:hover": {
                              backgroundColor: colors.grey[700], 
                            },
                          }}
                          disabled={!isChecked}
                        >
                        Finalizar
                      </Button>
                    </Box>
                  </Box>
                </Fade>
              </Modal>              
            </Box>
          </form>
        )}
      </Formik>
    </Box>
  );
};

