    const [propriedade, setPropriedade] = useState("");
    const [safra, setSafra] = useState("");
    const [glebas, setGlebas] = useState([]);
    const [custosRealizados,setCustosRealizados] = useState([]);
    const [custosPlanejados,setCustosPlanejados] = useState([]);
    const [open, setOpen] = useState(false);
    const [isChecked, setIsChecked] = useState(false);
    const [isHigher, setIsHigher] = useState(false)

    const headerNames = [
        "Cultivo",
        "Semente",
        "Dosagem",
        "Toneladas",
        "Adubo",
        "Fim Plantio",
        "Fim Colheita",
        "Tempo Lavoura",
        "Preção Milimetrica",
        "Umidade",
        "Impureza",
        "Grãos Avariados",
        "Grãos Esverdeados",
        "Grãos Quebrados",
    ];

    const comparativoProd = [
        "Prod. Prevista",
        "Prod. Realizada",
        "Comparativo",
    ]

    const fieldNames = [
        "crop",
        "seed",
        "dosage",
        "tons",
        "fertilizer",
        "plantingEndDate",
        "harvestEndDate",
        "fieldDuration",
        "rainfall",
        "moisture",
        "impurity",
        "damagedGrains",
        "greenGrains",
        "brokenGrains",
        "expectedYield",
        "actualYield",
        "comparativo",
    ];

    const columns = [
        { field: "category", headerName: "Categoria", flex: 1, minWidth: 100, resizable: false },
        { field: "name", headerName: "Nome", flex: 1, minWidth: 100, resizable: false },
        { field: "unit", headerName: "Unidade", flex: 1,minWidth: 100, resizable: false },
        { field: "quantity", headerName: "Quantidade", flex: 1, minWidth: 100, resizable: false },
        { field: "price", headerName: "Preço", flex: 1,  minWidth: 100, resizable: false },
        { field: "totalValue", headerName: "Valor Total", flex: 1, minWidth: 100,  resizable: false },
        { field: "expirationDate", headerName: "Data", flex: 1, minWidth: 100, resizable: false },
        { field: "note", headerName: "Observação", flex: 1, minWidth: 100, resizable: false },
        {
            field: "actions",
            headerName: "Ações",
            flex: 1,
            minWidth: 100,
            renderCell: (params) => {
                const { id } = params.row;

                return (
                    <Box 
                        display="flex" 
                        justifyContent="center" 
                        width="100%"
                        m="10px auto"
                    >
                        {isMobile ? (
                            <>
                                <Tooltip title="Visualizar">
                                    <IconButton onClick={() => handleView(id)} sx={{ color: colors.greenAccent[500]}}>
                                        <VisibilityIcon />
                                    </IconButton>
                                </Tooltip>
                            </>
                        ):(
                            <>
                                <Tooltip title="Visualizar">
                                    <Button
                                        variant="contained"
                                        sx={{
                                            backgroundColor: colors.greenAccent[500],
                                            "&:hover": {
                                                backgroundColor: colors.grey[700], 
                                            },
                                        }}
                                        onClick={() => handleView(id)}
                                    >
                                        <VisibilityIcon />
                                    </Button>
                                </Tooltip>
                            </>
                        )}
                    </Box>
                );
            },
            headerAlign: "center"
        },

    ];

    const glebasColumns = [
        { field: "name", headerName: "Nome", flex: 1,minWidth: 100, cellClassName: "name-column--cell", resizable: false },
        {
            field: "property",
            headerName: "Propriedade",
            flex: 1,
            minWidth: 100,
            cellClassName: "propertie-column--cell",
            resizable: false,
            renderCell: (params) => {
                const property = params.row.property;  
                return property ? property.name : "";  
            },
        },
        { field: "area", headerName: "Área", type: "number", flex: 1, minWidth: 100, headerAlign: "left", align: "left", resizable: false },
        {
