                                    <Typography sx={{ ml: "5px", fontWeight: "bold" }}>
                                        {access === "owner" ? "Proprietário" : "Permissão"}
                                    </Typography>
                                )}
                            </Box>
                        </Tooltip>
                    </Box>
                );
