                            {/* Linha de baixo */} 
                            <Box
                                gridColumn="span 12"
                                display="grid"
                                gridTemplateColumns={isMobile ? "repeat(2, 1fr)" : "repeat(4, 1fr)"}
                                gap="15px"
                            >
                                <Box display="flex" alignItems={isMobile ? "flex-start":"center" } marginBottom="15px" flexDirection={isMobile ? "column":"row" }>
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginBottom="5px" marginRight="10px">
                                        Prod. Prevista:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                        {safra.expectedYield}
                                    </Typography>
                                </Box>

                                <Box display="flex" alignItems={isMobile ? "flex-start":"center" } marginBottom="15px" flexDirection={isMobile ? "column":"row" }>
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginBottom="5px" marginRight="10px">
                                    Prod. Realizada:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                        {safra.actualYield}
                                    </Typography>
                                </Box>

                                <Box display="flex" alignItems={"center" } marginBottom="15px">
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginBottom="5px" marginRight="10px">
                                    Comparativo:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    <Box
                                        width="100%"
                                        p="5px"
                                        display="flex"
                                        justifyContent="center"
                                        alignItems="center"
                                        backgroundColor={isHigher ? colors.mygreen[500] : colors.redAccent[500]} 
                                        borderRadius="4px"
                                        color={"#fff" }
                                    >
                                        {isHigher ? <ArrowUpwardIcon /> : <ArrowDownwardIcon />} 
                                    </Box>
                                    </Typography>
                                </Box>
                                
                            </Box>
                            <Box
                                gridColumn="span 12"
                                display="grid"
                                alignItems="flex-end"
                                justifyContent="flex-end"
                            >
                            {userData && owner && userData.email === owner.email &&  (
                                    <Box 
                                        display="flex" 
                                        justifyContent="flex-end" 
                                        alignItems="flex-end" 
                                        flexGrow={1} 
                                        width="100%"
                                        marginTop={isMobile ?"20px": "-30px"}
                                    >
                                        <Tooltip title='Deletar'>
                                            <Button 
                                                
                                                variant="contained" 
                                                onClick={handleOpen} 
                                                sx={{ backgroundColor:  colors.redAccent[500],
                                                    "&:hover": {
                                                        backgroundColor: colors.grey[700], 
                                                    },
                                                }} 
                                            >
                                                <DeleteIcon />
                                            </Button>
                                        </Tooltip>
                                        <Modal
                                            open={open}
                                            onClose={null} 
                                            aria-labelledby="transition-modal-title"
                                            aria-describedby="transition-modal-description"
                                            closeAfterTransition
                                            slots={{ backdrop: Backdrop }}
                                            slotProps={{
                                            backdrop: {
                                                timeout: 500,
                                            },
                                            }}
                                        >
                                            <Fade in={open}>
                                                <Box 
                                                color={colors.grey[100]}
                                                backgroundColor={colors.primary[400]}

                                                    sx={{ 
                                                        position: 'absolute',
                                                        top: '50%',
                                                        left: '50%',
                                                        transform: 'translate(-50%, -50%)',
                                                        width: 450,
                                                        borderRadius: 3, 
                                                        boxShadow: '0px 10px 30px rgba(0, 0, 0, 0.1)',
                                                        p: 4,

                                                    }}
                                                >
                                                    <Typography id="modal-modal-title" variant="h4" component="h2">
                                                        Deseja realmente deletar esta Safra?
                                                    </Typography>
                                                    <Typography id="modal-modal-description" sx={{ mt: 2 }}>
                                                        Ao fazer isso, esteja ciente que:
                                                        <ul>
                                                            <li>Essa ação não pode ser revertida;</li>
                                                            <li>Os dados de custos relacionados a esta safra também serão deletados.</li>
                                                        </ul>
                                                    </Typography>
                                                    
                                                    <FormControlLabel
                                                        control={
                                                            <Checkbox
                                                                checked={isChecked}
                                                                onChange={handleCheckboxChange} 
                                                            />
                                                        }
                                                        label="Estou ciente e quero continuar."
                                                        sx={{ mt: 2 }}
                                                    />
                                                    
                                                    <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
                                                        <Button 
                                                            onClick={handleClose} 
                                                            sx={{
                                                                color: colors.redAccent[500]
                                                            }}
                                                        >
                                                            Cancelar
                                                        </Button>
                                                        <Button 
                                                            onClick={handleDelete} 
                                                            variant="contained" 
                                                            sx={{ backgroundColor:  colors.redAccent[500],
                                                                "&:hover": {
                                                                    backgroundColor: colors.grey[700], 
                                                                },
                                                            }}
                                                            disabled={!isChecked} 
                                                        >
                                                            Deletar
                                                        </Button>
                                                    </Box>
                                                </Box>
                                            </Fade>
                                        </Modal>
                                        <Tooltip title='Editar'>
                                            <Button 
                                                disabled={safra.status === true}
                                                variant="contained" 
                                                onClick={() => handleEdit()} 
