                                </Box>  
                                <Box display="flex" alignItems="center" marginBottom="15px">
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginRight="10px">
                                    Unidade:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    {custo.unit}
                                    </Typography>
                                </Box>                                
                            </Box>

                            {/* Segunda Coluna */}
                            <Box  gridColumn={isMobile ? "span 12" : "span 1"} display="flex" flexDirection="column" alignItems="flex-start">
                                <Box display="flex" alignItems="center" marginBottom="15px">
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginRight="10px">
                                    Data de Validade:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    {custo.expirationDate}
                                    </Typography>
                                </Box>
                                <Box display="flex" alignItems="center" marginBottom="15px" >
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginRight="10px">
                                    Quantidade:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    {custo.quantity}
                                    </Typography>
                                </Box>
                                <Box display="flex" alignItems="center"  marginBottom="15px">
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginRight="10px">
                                    Preço:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    {custo.price}
                                    </Typography>
                                </Box>
                                <Box display="flex" alignItems="center" >
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginRight="10px">
                                    Valor Total:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    {custo.totalValue}
                                    </Typography>
                                </Box>
                            </Box>

                            <Box gridColumn="span 12" flexDirection="column" alignItems="flex-start" marginTop={isMobile ? "15px" : "0px"}>
                                <Box display="flex" alignItems="center">
                                    <Typography variant="h6" fontWeight="bold" color={colors.grey[100]} marginRight="10px">
                                    Observações:
                                    </Typography>
                                    <Typography variant="body1" color={colors.grey[300]}>
                                    {custo.note}
                                    </Typography>
                                </Box>
                            </Box>
                            <Box
                                gridColumn="span 12"
                                display="grid"
                                alignItems="flex-end"
                                justifyContent="flex-end"
                                //sx={{border: "1px solid red"}} 
                            >
                                {userData &&  (
                                        <Box 
                                            display="flex" 
                                            justifyContent= {isMobile ? "flex-start" : "flex-end"} 
                                            alignItems="flex-end" 
                                            flexGrow={1} 
                                            width="100%"
                                        >
                                            <Tooltip title='Deletar'>
                                                <Button 
                                                    variant="contained" 
                                                    onClick={handleOpenDelete} 
                                                    sx={{ backgroundColor:  colors.redAccent[500],
                                                        "&:hover": {
                                                            backgroundColor: colors.grey[700], 
                                                        },
                                                    }} 
                                                >
                                                    <DeleteIcon />
                                                </Button>
                                            </Tooltip>
                                            <Modal
                                                open={openDelete}
                                                onClose={null} 
                                                aria-labelledby="transition-modal-title"
                                                aria-describedby="transition-modal-description"
                                                closeAfterTransition
                                                slots={{ backdrop: Backdrop }}
                                                slotProps={{
                                                backdrop: {
                                                    timeout: 500,
                                                },
                                                }}
                                            >
                                                <Fade in={openDelete}>
                                                    <Box 
                                                    color={colors.grey[100]}
                                                    backgroundColor={colors.primary[400]}
                                                        sx={{ 
                                                            position: 'absolute',
                                                            top: '50%',
                                                            left: '50%',
                                                            transform: 'translate(-50%, -50%)',
                                                            width: 450,
                                                            borderRadius: 3, 
                                                            boxShadow: '0px 10px 30px rgba(0, 0, 0, 0.1)',
                                                            p: 4,
                                                        }}
                                                    >
                                                        <Typography id="modal-modal-title" variant="h4" component="h2">
                                                            Deseja realmente deletar este item do estoque?
                                                        </Typography>
                                                        <Typography id="modal-modal-description" sx={{ mt: 2 }}>
                                                            Ao fazer isso, esteja ciente que:
                                                            <ul>
                                                                <li>Essa ação não pode ser revertida.</li>
                                                            </ul>
                                                        </Typography>
                                                        
                                                        <FormControlLabel
                                                            control={
                                                                <Checkbox
                                                                    checked={isChecked}
                                                                    onChange={handleCheckboxChange} 
                                                                />
                                                            }
                                                            label="Estou ciente e quero continuar."
                                                            sx={{ mt: 2 }}
                                                        />
                                                        
                                                        <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
                                                            <Button 
                                                                onClick={handleCloseDelete} 
                                                                sx={{
                                                                    color: colors.redAccent[500]
                                                                }}
                                                            >
                                                                Cancelar
                                                            </Button>
                                                            <Button 
                                                                onClick={handleDelete} 
                                                                variant="contained" 
                                                                sx={{ backgroundColor:  colors.redAccent[500],
                                                                    "&:hover": {
                                                                        backgroundColor: colors.grey[700], 
                                                                    },
                                                                }}
                                                                disabled={!isChecked} 
                                                            >
                                                                Deletar
                                                            </Button>
                                                        </Box>
                                                    </Box>
                                                </Fade>
                                            </Modal>
                                            <Tooltip title='Editar'>
                                                <Button 
                                                    variant="contained" 
                                                    onClick={() => handleEdit()} 
                                                    sx={{ml:2,
                                                        backgroundColor:colors.orangeAccent[500],
                                                        "&:hover": {
                                                            backgroundColor: colors.grey[700], 
                                                        },
                                                    }}
                                                >
                                                    <EditIcon />
                                                </Button>
                                            </Tooltip>
                                            <Tooltip title='Transferir'>
                                                <Button 
                                                    variant="contained" 
                                                    onClick={handleOpenTransfer} 
                                                    sx={{ ml:2,
                                                        backgroundColor:colors.blueAccent[500],
                                                        "&:hover": {
                                                            backgroundColor: colors.grey[700], 
                                                        },
                                                    }} 
                                                >
                                                    <ImportExportIcon />
                                                </Button>
                                            </Tooltip>
                                            <Modal
                                                open={openTransfer}
                                                onClose={null} 
                                                aria-labelledby="transition-modal-title"
                                                aria-describedby="transition-modal-description"
                                                closeAfterTransition
                                                slots={{ backdrop: Backdrop }}
                                                slotProps={{
                                                backdrop: {
                                                    timeout: 500,
                                                },
                                                }}
                                            >
                                                <Fade in={openTransfer}>
                                                    <Box 
                                                    color={colors.grey[100]}
                                                    backgroundColor={colors.primary[400]}
                                                        sx={{ 
                                                            position: 'absolute',
                                                            top: '50%',
                                                            left: '50%',
                                                            transform: 'translate(-50%, -50%)',
                                                            width: 450,
                                                            borderRadius: 3, 
                                                            boxShadow: '0px 10px 30px rgba(0, 0, 0, 0.1)',
                                                            p: 4,
                                                        }}
                                                    >
                                                        <Typography id="modal-modal-title" variant="h4" component="h2">
                                                            Transferir item de estoque para safra
                                                        </Typography>
                                                        <Formik
                                                            onSubmit={handleFormSubmit}
                                                            initialValues={initialValues}
                                                            validationSchema={checkoutSchema}
                                                        >
                                                            {({
                                                                  values,
                                                                  errors,
                                                                  touched,
                                                                  handleBlur,
                                                                  handleChange,
                                                                  handleSubmit,
                                                                  setFieldValue
                                                            }) => (
                                                                  <form onSubmit={handleSubmit}>
                                                                    <Autocomplete
                                                                        disablePortal
                                                                        id="safra"
                                                                        options={safraOptions} 
                                                                        getOptionLabel={(option) => option.name || ""} 
                                                                        name="safra"
                                                                        value={
                                                                            values.safra 
                                                                            ? safraOptions.find((option) => option.id === values.safra) 
                                                                            : null
                                                                        } 
                                                                        onChange={(event, value) => {
                                                                            setFieldValue('safra', value?.id || null);
                                                                                    
                                                                            if (value) {
                                                                                fetchGlebaData(value.id); 
                                                                            }
                                                                        }}                      
                                                                        onBlur={handleBlur} 
                                                                        sx={{ 
                                                                            gridColumn: isSmallDevice ? "span 4" : "span 2",
                                                                            mt: 5 
                                                                        }}
                                                                        renderInput={(params) => (
                                                                            <TextField 
                                                                                {...params} 
                                                                                label="Safra"
                                                                                variant="filled"
                                                                                name="safra"
                                                                                error={!!touched.safra && !!errors.safra}
                                                                                helperText={touched.safra && errors.safra}
                                                                                onBlur={handleBlur} 
                                                                            />
                                                                        )}
                                                                    />
                                                                    <Autocomplete
                                                                        disablePortal
                                                                        id="gleba"
                                                                        options={glebaOptions} 
                                                                        getOptionLabel={(option) => option.name || ""} 
                                                                        name="gleba"
                                                                        value={
                                                                            values.gleba 
                                                                            ? glebaOptions.find((option) => option.id === values.gleba) 
                                                                            : null
                                                                        } 
                                                                        onChange={(event, value) => setFieldValue('gleba', value?.id || null)} 
                                                                        onBlur={handleBlur} 
                                                                        sx={{ 
                                                                            gridColumn: isSmallDevice ? "span 4" : "span 2", 
                                                                            mt: 5
                                                                        }}
                                                                        renderInput={(params) => (
                                                                            <TextField 
                                                                                {...params} 
                                                                                label="Talhão"
                                                                                variant="filled"
                                                                                name="gleba"
                                                                                error={!!touched.gleba && !!errors.gleba}
                                                                                helperText={touched.gleba && errors.gleba}
                                                                                onBlur={handleBlur} 
                                                                            />
                                                                        )}
                                                                        noOptionsText="Nenhum talhão disponível"
                                                                    />   
                                                                    <TextField
                                                                        id="quantity"  
                                                                        label="Quantidade"
                                                                        type="number"  
                                                                        name="quantity"  
                                                                        value={values.quantity}  
                                                                        onChange={handleChange}  
                                                                        onBlur={handleBlur}  
                                                                        error={!!touched.quantity && !!errors.quantity} 
                                                                        helperText={touched.quantity && errors.quantity}  
                                                                        variant="filled"
                                                                        fullWidth
                                                                        sx={{ 
                                                                            mt: 5
                                                                        }}
                                                                    />      
                                                                    <Typography id="modal-modal-description" sx={{ mt: 2 }}>
                                                                        Deseja realmente transferir este item do estoque para um custo da safra?
                                                                        Ao fazer isso, esteja ciente que:
                                                                        <ul>
                                                                            <li>Essa ação não pode ser revertida.</li>
                                                                        </ul>
                                                                    </Typography>
                                                                    
                                                                    <FormControlLabel
                                                                        control={
                                                                            <Checkbox
                                                                                checked={isChecked}
                                                                                onChange={handleCheckboxChange} 
                                                                            />
                                                                        }
                                                                        label="Estou ciente e quero continuar."
                                                                        sx={{ mt: 2 }}
                                                                    />
                                                                    
                                                                    <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 3 }}>
                                                                        <Button 
                                                                            onClick={handleCloseTransfer} 
                                                                            sx={{
                                                                                color: colors.redAccent[500]
                                                                            }}
                                                                        >
                                                                            Cancelar
                                                                        </Button>
                                                                        <Button 
                                                                            type="submit"
                                                                            variant="contained" 
                                                                            sx={{ backgroundColor:  colors.blueAccent[500],
                                                                                "&:hover": {
                                                                                    backgroundColor: colors.grey[700], 
                                                                                },
                                                                            }}
                                                                            disabled={!isChecked} 
                                                                        >
                                                                            Transferir
                                                                        </Button>
                                                                    </Box>                                               
                                                                  </form>
                                                                )}
                                                        </Formik>
 
                                                        
                                                    </Box>
                                                </Fade>
                                            </Modal>
                                        </Box>
                                    )}
                            </Box>
                        </Box>
                    </Box>
            </Box>
        </Box>
    );
};

const checkoutSchema = yup.object().shape({
    quantity: yup
        .number()
        .required("Campo de preenchimento obrigatório")
        .positive("Deve ser um número positivo")
        .test(
        'quantity-greater-than-custo', 
        'A quantidade não pode ser maior que o disponível em estoque', 
        function(value) {
            const { storageQuantity } = this.parent; 
            return value <= storageQuantity;  
        }
    ),    
    safra: yup.string().required("Campo de preenchimento obrigatório"),
    gleba: yup.string().required("Campo de preenchimento obrigatório"),    
});

export default StoragePage;
